import{A as e,z as r,y as n}from"./chunks/theme.BnJirLdI.js";import{u as a}from"./chunks/link-icons.fvmyrjZg.js";import{a3 as o,o as i,c as s,ah as l}from"./chunks/framework.cbxun9lb.js";const m=JSON.parse('{"title":"Pointeract","titleTemplate":"Lightweight and Extensible Human Interaction Library","description":"Pointeract is a tiny (1KB core), tree-shakable TypeScript library for robust human gesture detection. Supports mouse, touch, touchpad, and wheel events. A modern, extensible alternative to Hammer.js.","frontmatter":{"layout":"project","title":"Pointeract","titleTemplate":"Lightweight and Extensible Human Interaction Library","description":"Pointeract is a tiny (1KB core), tree-shakable TypeScript library for robust human gesture detection. Supports mouse, touch, touchpad, and wheel events. A modern, extensible alternative to Hammer.js.","logo":"https://pointeract.consensia.cc/logo.svg","links":[{"name":"Documentation","url":"https://pointeract.consensia.cc","color":"#425aef"},{"name":"GitHub Repository","url":"https://github.com/hesprs/pointeract","color":"#010409"},{"name":"npm","url":"https://www.npmjs.com/package/pointeract","color":"#EA2039"}],"head":[["meta",{"name":"keywords","content":"Pointeract, JavaScript, TypeScript, JavaScript gesture library, Hammer.js alternative, pan zoom, touchpad, tree-shakable, mouse wheel, multitouch gestures, drag and drop, swipe detection"}]]},"headers":[],"relativePath":"projects/pointeract.md","filePath":"en/projects/pointeract.md","lastUpdated":1777982901000}'),d={name:"projects/pointeract.md"},y=o({...d,setup(c){return a({Documentation:n,npm:r,"GitHub Repository":e}),(g,t)=>(i(),s("div",null,[...t[0]||(t[0]=[l('<h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to “Introduction”">​</a></h2><p>Pointeract is a tiny JavaScript/TypeScript utility library focusing on one thing - handling user interactions with DOM elements, e.g. multitouch and touchpad.</p><p>With the unique strength of versatile typings in TypeScript and its dynamic nature, Pointeract has achieved a highly <em>modular, extendable and efficient</em> architecture. Its core bundle size is only <strong>1KB</strong> minified + gzipped, functionalities come from also byte-sized modules. It&#39;s fully <strong>tree-shakable</strong>, the fewer modules you use, the smaller your bundle is.</p><p>Homepage &amp; Documentation: <a href="https://pointeract.consensia.cc" target="_blank" rel="noreferrer">pointeract.consensia.cc</a>.</p><h2 id="supported-features" tabindex="-1">Supported Features <a class="header-anchor" href="#supported-features" aria-label="Permalink to “Supported Features”">​</a></h2><ul><li><strong>Click (Double Click, Triple Click, Quadruple Click, Any Click)</strong></li><li><strong>Drag</strong></li><li><strong>Swipe (All directions, single / multiple fingers)</strong></li><li><strong>Pan and Zoom via Mouse Wheel (<code>ctrl</code>/<code>shift</code> key binding, touchpad support)</strong></li><li><strong>Pan and Zoom via Multitouch (Pan, Pinch)</strong></li><li><strong>One-line Prevent Default</strong></li><li><strong>Smooth Everything (drag / pan / zoom / any interaction involving numbers)</strong></li></ul><p>Those interactions are shipped via modules, which can be composed from a single drag-and-drop to a canvas app.</p><p>Missing your desired interaction? <a href="https://pointeract.consensia.cc/development/custom-modules" target="_blank" rel="noreferrer">Write your own module</a>!</p><h2 id="advantages" tabindex="-1">Advantages <a class="header-anchor" href="#advantages" aria-label="Permalink to “Advantages”">​</a></h2><ul><li><strong>🐣 Tiny</strong>: With base <strong>1KB</strong> minified and gzipped, <strong>1-2KB</strong> for normal usage.</li><li><strong>💪 Robust</strong>: Excels at complex gestures where most interaction libraries fail, <a href="https://pointeract.consensia.cc/development/testing#monkey-test" target="_blank" rel="noreferrer">Why?</a></li><li><strong>🧩 Extensible</strong>: Extend Pointeract effortlessly via our module API.</li><li><strong>🔌 Flexible during Runtime</strong>: Options are updated reactively. Stop/start any module during runtime.</li><li><strong>🛡️ Safe</strong>: Not modifying the DOM (except the <code>PreventDefault</code> module). Meticulous clean up prevents memory leaks.</li></ul><h2 id="how-pointeract-stands-out" tabindex="-1">How Pointeract Stands Out? <a class="header-anchor" href="#how-pointeract-stands-out" aria-label="Permalink to “How Pointeract Stands Out?”">​</a></h2><p>There&#39;re already plenty of interaction libraries out there, most famous ones are <code>d3-drag</code> + <code>d3-zoom</code>, <code>Interact.js</code> and <code>Hammer.js</code>, but Pointeract is different.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Criteria</th><th style="text-align:center;">Pointeract</th><th style="text-align:center;"><a href="https://github.com/d3/d3-drag" target="_blank" rel="noreferrer">D3 Drag</a> + <a href="https://github.com/d3/d3-zoom" target="_blank" rel="noreferrer">D3 Zoom</a></th><th style="text-align:center;"><a href="https://hammerjs.github.io" target="_blank" rel="noreferrer">Hammer.js</a></th><th style="text-align:center;"><a href="https://interactjs.io" target="_blank" rel="noreferrer">Interact.js</a></th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Written in TypeScript?</strong></td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td></tr><tr><td style="text-align:left;"><strong>Tree-shakeable?</strong></td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td></tr><tr><td style="text-align:left;"><strong>Total Bundle Size (Minified + Gzipped)</strong></td><td style="text-align:center;">👑 <a href="https://bundlejs.com/?q=pointeract%40latest" target="_blank" rel="noreferrer">2.7KB</a></td><td style="text-align:center;"><a href="https://bundlejs.com/?q=d3-drag%403.0.0%2Cd3-zoom%403.0.0" target="_blank" rel="noreferrer">17KB</a></td><td style="text-align:center;"><a href="https://bundlejs.com/?q=hammerjs%402.0.8" target="_blank" rel="noreferrer">7KB</a></td><td style="text-align:center;"><a href="https://bundlejs.com/?q=interactjs%401.10.27" target="_blank" rel="noreferrer">28KB</a></td></tr><tr><td style="text-align:left;"><strong>Last Updated</strong></td><td style="text-align:center;">👑 Actively Maintained</td><td style="text-align:center;">2021</td><td style="text-align:center;">2015</td><td style="text-align:center;">2023</td></tr><tr><td style="text-align:left;"><strong>Versatility</strong></td><td style="text-align:center;">Pointer and Wheel Related + Some Utils</td><td style="text-align:center;">👑 Pointer and Wheel Related + Ecosystem</td><td style="text-align:center;">Pointer Related</td><td style="text-align:center;">Pointer Related + Comprehensive Utils</td></tr><tr><td style="text-align:left;"><strong>Support</strong></td><td style="text-align:center;">👑 Mouse, Mouse Wheel, Touch, and Touchpad</td><td style="text-align:center;">⚠️ No Touchpad Support</td><td style="text-align:center;">⚠️ No Touchpad or Mouse Wheel Support</td><td style="text-align:center;">⚠️ No Touchpad or Mouse Wheel Support</td></tr><tr><td style="text-align:left;"><strong>Robust (Passes <a href="https://pointeract.consensia.cc/development/testing#monkey-test" target="_blank" rel="noreferrer">Monkey Test</a>)</strong></td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌ Element Jerks</td><td style="text-align:center;">❌ Element Ignores the Second Touch</td></tr><tr><td style="text-align:left;"><strong>Extensible?</strong></td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td></tr></tbody></table><h2 id="license" tabindex="-1">License <a class="header-anchor" href="#license" aria-label="Permalink to “License”">​</a></h2><p>Pointeract is licensed under the <a href="https://www.apache.org/licenses/LICENSE-2.0.html" target="_blank" rel="noreferrer">Apache License 2.0</a>.</p>',15)])]))}});export{m as __pageData,y as default};
